const data = $node["Telegram"].json["result"];
const extraData = $node["Get FullChannel & Participants"].json;

const participants = extraData["Participants"];
admins = participants["participants"].filter(item => item["className"] == "ChannelParticipantAdmin");

const query = 
`
DECLARE @ChatId BIGINT = ${ data["id"] };
DECLARE @Title NVARCHAR(MAX) = N'${data["title"]}';
DECLARE @Username NVARCHAR(MAX) = N'${data['username']}';
DECLARE @Type NVARCHAR(MAX) = N'${data["type"]}';
DECLARE @Description NVARCHAR(MAX) = N'${data["description"] ?? ""}';
DECLARE @LinkedChatId BIGINT = ${data["linked_chat_id"] ?? null};
DECLARE @ActiveUsernames NVARCHAR(MAX) = N'${JSON.stringify(data["active_usernames"])}';
DECLARE @Members NVARCHAR(MAX) = N'${JSON.stringify(participants).replace(/'/g, "''") }';
DECLARE @Administrators NVARCHAR(MAX) = N'${JSON.stringify(admins).replace(/'/g, "''") }';
DECLARE @InviteLink NVARCHAR(MAX) = N'${data["invite_link"]}';
DECLARE @ExtraData NVARCHAR(MAX) = N'${JSON.stringify({"extraData": extraData, "data": data}).replace(/'/g, "''") }';
DECLARE @UpdatedDateTime DATETIMEOFFSET(7) = GETDATE(); 
DECLARE @SyncStatus NVARCHAR(50) = N'SYNCED';


UPDATE [dbo].[TelegramGroups]
SET 
    [ChatId] = @ChatId,
    [Title] = @Title,
    [Username] = @Username,
    [Type] = @Type,
    [Description] = @Description,
    [LinkedChatId] = @LinkedChatId, 
    [ActiveUsernames] = @ActiveUsernames,
    [Members] = @Members,
    [Administrators] = @Administrators,
    [InviteLink] = @InviteLink,
    [ExtraData] = @ExtraData,
    [UpdatedDateTime] = @UpdatedDateTime,
    [SyncStatus] = @SyncStatus
WHERE [Username] = @Username;

SELECT TOP 1 1;
`

return {
  query: query
}

