let queries = [];

for (const item of $input.all()) {
  const query = 
    `
    IF EXISTS (SELECT 1 FROM [dbo].[TelegramUserBots] WHERE Username = N'${item.json['Username']}')
BEGIN
    UPDATE [dbo].[TelegramUserBots]
    SET 
        Token = N'${item.json['Token']}',  
        Owner = N'${ item.json["Owner"] }', 
        UpdatedDateTime = GETDATE(),
        SyncStatus = NULL
    WHERE Username = N'${item.json['Username']}';
END
ELSE
BEGIN
    INSERT INTO [dbo].[TelegramUserBots] (
      Username, 
      Token, 
      Owner,
      UpdatedDateTime)
    VALUES (
      N'${item.json['Username']}', 
      N'${item.json['Token']}', 
      N'${ item.json["Owner"] }',  
      GETDATE());
END
    `;

  queries.push(query);
}

return {
  query: queries.join('\n') + '\n' + 'SELECT TOP 1 1;'
};

